2	\chapter{Sheaves of \(k\)-modules: sheafification, Ext, and the structure sheaf as a sheaf of \(k\)-modules}
3	\label{chap:Cohomology_StructureSheafModuleK}
4	
5	This chapter implements Phase~A step~5: equipping \(H^1(C, \mathcal O_C)\) with a \(k\)-vector-space structure when \(C\) is a scheme over \(\Spec k\). The route is through the linear enrichment of the sheaf category over \(k\), which automatically provides a \(k\)-module structure on \(\Ext\) groups in any \(k\)-linear abelian category. The chapter introduces no protected declarations: every instance and definition here is auxiliary, supporting the construction of \(H^1(C, \mathcal O_C)\) in Definition~REF.
6	
7	The chapter splits into two parts. Sections~REF--REF provide the typeclass plumbing: sheafification and \(\Ext\) for sheaves valued in \(k\)-modules. Section~REF provides the substantive content: the \(k\)-module-valued structure sheaf for a scheme over \(\Spec k\), built from the algebra map induced by the structure morphism. Together these complete Phase~A step~5; the final remaining piece for an honest definition of genus is Phase~A step~6 (Serre finiteness, multi-iteration).
8	
9	\section{Sheafification of \(k\)-module-valued sheaves on opens}
10	\label{sec:moduleK_prereqs}
11	
12	\begin{theorem}\leanok
13	[Sheafification on the topology of opens, \(k\)-module valued]
14	  \label{thm:HasSheafify_Opens_ModuleCatK}
15	  \lean{AlgebraicGeometry.Cohomology.instHasSheafify_Opens_ModuleCatK}
16	  Let \(k\) be a commutative ring and \(X\) a topological space. Then the Grothendieck topology of opens of \(X\) admits sheafification for sheaves valued in the category of \(k\)-modules.
17	\end{theorem}
18	
19	\begin{proof}
20	
21	
22	\leanok
23	  Mathlib's general sheafification API constructs sheafification whenever weak sheafification holds and the resulting sheafification preserves finite limits. For the topology of opens and the category of \(k\)-modules, both prerequisites are available in Mathlib. The instance is therefore inferable; the formal task is the universe pinning, mirroring the abelian-group analogue (Theorem~REF).
24	\end{proof}
25	
26	\section{\(\Ext\) for \(k\)-module-valued sheaves on opens}
27	\label{sec:moduleK_ext}
28	
29	\begin{theorem}\leanok
30	[\(\Ext\) on the topology of opens, \(k\)-module valued]
31	  \label{thm:HasExt_Sheaf_Opens_ModuleCatK}
32	  \lean{AlgebraicGeometry.Cohomology.instHasExt_Sheaf_Opens_ModuleCatK}
33	  
34	  Let \(k\) be a commutative ring and \(X\) a topological space. Then the category of sheaves of \(k\)-modules on the topology of opens of \(X\) admits \(\Ext\) groups.
35	\end{theorem}
36	
37	\begin{proof}
38	
39	
40	\leanok
41	  The category of \(k\)-modules is abelian. The sheaf category inherits an abelian structure from an abelian value category once sheafification is available (Theorem~REF). Mathlib's standard construction produces \(\Ext\) from any abelian category. The universe annotation matches the morphism universe of the sheaf category, mirroring the abelian-group analogue (Theorem~REF).
42	\end{proof}
43	
44	\section{The structure sheaf of a \(\Spec k\)-scheme as a sheaf of \(k\)-modules}
45	\label{sec:scheme_toModuleKSheaf}
46	
47	This section provides the substantive content of Phase~A step~5. For \(C\) a scheme over \(\Spec k\), the structure morphism \(C \to \Spec k\) induces an algebra map \(k \to \Gamma(C, U)\) for every open \(U \subseteq C\). This equips the structure sheaf with a sheaf-of-\(k\)-modules structure.
48	
49	\subsection{The algebra map from the structure morphism}
50	
51	For each open \(U \subseteq C\), the structure morphism induces a chain of ring maps
52	\[
53	  k \xrightarrow{\cong} \Gamma(\Spec k, \top) \xrightarrow{C.\mathrm{hom}} \Gamma(C, C.\mathrm{hom}^{-1}\top) \xrightarrow{\rho} \Gamma(C, U),
54	\]
55	where \(\rho\) is the restriction along \(U \le C.\mathrm{hom}^{-1}\top = \top\).
56	
57	\begin{definition}\leanok
58	[Algebra map on a section]
59	  \label{def:Scheme_kToSection}
60	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection}
61	  
62	  Let \(k\) be a commutative ring and \(C\) a scheme over \(\Spec k\). For any open \(U\) of \(C\), define the ring map \(k \to \Gamma(C, U)\) to be the composition of the inverse of the canonical isomorphism \(\Gamma(\Spec k, \top) \cong k\), the structure morphism map on global sections, and the restriction from \(\top\) to \(U\).
63	\end{definition}
64	
65	\begin{definition}\leanok
66	[Algebra structure on a section]
67	  \label{def:Scheme_algebraSection}
68	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraSection}
69	  
70	  The ring map of Definition~REF exhibits \(\Gamma(C, U)\) as a \(k\)-algebra.
71	\end{definition}
72	
73	\begin{lemma}\leanok
74	[Defining identity for the algebra map]
75	  \label{lem:Scheme_algebraMap_eq_kToSection}
76	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_eq_kToSection}
77	  
78	  Under the algebra structure of Definition~REF, the structure map \(k \to \Gamma(C, U)\) equals the ring map of Definition~REF.
79	\end{lemma}
80	
81	\begin{proof}
82	  
83	  \leanok
84	  Definitionally true: converting a ring homomorphism to an algebra structure and extracting the structure map recovers the original homomorphism.
85	\end{proof}
86	
87	\subsection{Naturality of the algebra map}
88	
89	\begin{lemma}\leanok
90	[Restriction is compatible with the algebra map]
91	  \label{lem:Scheme_kToSection_naturality}
92	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection_naturality}
93	  
94	  For any inclusion \(V \le U\) of opens in \(C\), the algebra map commutes with restriction: the composition \(k \to \Gamma(C, U) \to \Gamma(C, V)\) equals the direct map \(k \to \Gamma(C, V)\).
95	\end{lemma}
96	
97	\begin{proof}
98	  
99	  \leanok
100	  Both sides factor through the structure morphism map on global sections. The remaining triangle commutes by functoriality of the presheaf on composable inclusions.
101	\end{proof}
102	
103	\begin{lemma}\leanok
104	[Algebra-map naturality]
105	  \label{lem:Scheme_algebraMap_naturality}
106	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_naturality}
107	  
108	  For any inclusion \(V \le U\) of opens in \(C\) and any \(r \in k\), the restriction map sends the image of \(r\) in \(\Gamma(C, U)\) to the image of \(r\) in \(\Gamma(C, V)\).
109	\end{lemma}
110	
111	\begin{proof}
112	  
113	  \leanok
114	  Lemma~REF reduces both sides to the underlying ring map of the algebra map; Lemma~REF then closes the goal by congruence.
115	\end{proof}
116	
117	\subsection{The presheaf of \(k\)-modules and its sheaf condition}
118	
119	\begin{definition}\leanok
120	[Presheaf of \(k\)-modules from \(\mathcal O_C\)]
121	  \label{def:Scheme_toModuleKPresheaf}
122	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf}
123	  
124	  Define the presheaf of \(k\)-modules on \(C\) by sending each open \(U\) to the \(k\)-module \(\Gamma(C, U)\), with the \(k\)-action given by the algebra structure of Definition~REF, and on an inclusion \(V \le U\) by the restriction map viewed as a \(k\)-linear map. Functoriality reduces to the presheaf axioms of \(\mathcal O_C\).
125	\end{definition}
126	
127	\begin{theorem}\leanok
128	[Sheaf condition]
129	  \label{thm:Scheme_toModuleKPresheaf_isSheaf}
130	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf_isSheaf}
131	  
132	  The presheaf of Definition~REF is a sheaf for the Grothendieck topology of opens of \(C\).
133	\end{theorem}
134	
135	\begin{proof}
136	  
137	  \leanok
138	  By the concrete-category criterion, it suffices to show that the underlying presheaf of types is a sheaf. By construction, this composite agrees on objects and morphisms with the structure sheaf viewed as a presheaf of types. The latter is a sheaf because the structure sheaf is a sheaf of commutative rings.
139	\end{proof}
140	
141	\subsection{The structure sheaf as a sheaf of \(k\)-modules}
142	
143	\begin{definition}\leanok
144	[Structure sheaf as a sheaf of \(k\)-modules]
145	  \label{def:Scheme_toModuleKSheaf}
146	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf}
147	  
148	  Bundle Definition~REF and Theorem~REF into the sheaf of \(k\)-modules on \(C\).
149	\end{definition}
150	
151	\subsection{Forget-and-recover: bridging \(k\)-module and abelian-group values}
152	
153	\begin{definition}\leanok
154	[Forget-and-recover natural iso for the \(k\)-module structure sheaf]
155	  \label{def:Scheme_toModuleKSheaf_forgetCompare}
156	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf_forgetCompare}
157	  
158	  Let \(C\) be a scheme over \(\Spec k\). Then forgetting the \(k\)-module structure from the sheaf of Definition~REF yields a sheaf of abelian groups canonically isomorphic to the abelian-group-valued structure sheaf of Definition~REF.
159	\end{definition}
160	
161	\begin{proof}
162	  
163	  \leanok
164	  Definitionally true: both sides evaluate at every open \(U\) to the abelian group underlying \(\Gamma(C, U)\), and the action on morphisms is the underlying restriction map on both sides.
165	\end{proof}
166	
167	\begin{lemma}\leanok
168	[Object-evaluation lemma for the presheaf of \(k\)-modules]
169	  \label{lem:Scheme_toModuleKPresheaf_obj}
170	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf_obj}
171	  
172	  For every open \(U\) of \(C\), the value of the presheaf of Definition~REF at \(U\) is the \(k\)-module with carrier \(\Gamma(C, U)\).
173	\end{lemma}
174	
175	\begin{proof}
176	  
177	  \leanok
178	  Definitionally true by construction.
179	\end{proof}
180	
181	\section{Sheaf cohomology with \(k\)-module coefficients}
182	\label{sec:HModule}
183	
184	The abstract cohomology API is formulated for sheaves of abelian groups. To obtain a \(k\)-vector-space structure on \(H^n(C, \mathcal O_C)\), we build a parallel sheaf cohomology valued in \(k\)-modules. The sheaf category of \(k\)-modules already has \(\Ext\) (Theorem~REF), and \(\Ext\) groups in any \(k\)-linear abelian category carry a canonical \(k\)-module structure.
185	
186	\begin{definition}\leanok
187	[Sheaf cohomology with \(k\)-module coefficients]
188	  \label{def:Scheme_HModule}
189	  \lean{AlgebraicGeometry.Scheme.HModule}
190	  
191	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules and \(\Ext\). For a sheaf \(F\) of \(k\)-modules and \(n \in \mathbb N\), define the \(k\)-module-valued sheaf cohomology
192	  \[
193	    H^n_{\Module}(F) \;:=\; \Ext^n\bigl(\text{constant sheaf at }k,\; F\bigr).
194	  \]
195	  This automatically carries a \(k\)-module structure.
196	\end{definition}
197	
198	\begin{remark}[Lean implementation]
199	  The declaration uses a reducible wrapper (`abbrev` rather than `def`) so that instance synthesis sees through to the underlying \(\Ext\) group and finds both the \(k\)-module and abelian-group structures automatically. Under a non-reducible wrapper, `Module.finrank` would fail to typecheck.
200	\end{remark}
201	
202	\section{The \(H^0\) algebraic bridge}
203	\label{sec:HModule_zero}
204	
205	After Definition~REF the cohomology groups \(H^n_{\Module}(F)\) are well-defined and carry the canonical \(k\)-module structure. The next algebraic preliminary is the identification of the degree-zero piece \(H^0_{\Module}(F)\) with a \(\Hom\) group: the bridge from sheaf cohomology to representable Hom-functors.
206	
207	\begin{definition}\leanok
208	[\(H^0\) as a \(k\)-linear Hom group]
209	  \label{def:Scheme_HModule_zero_linearEquiv}
210	  \lean{AlgebraicGeometry.Scheme.HModule_zero_linearEquiv}
211	  
212	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules and \(\Ext\), and \(F\) a sheaf of \(k\)-modules. Then there is a canonical \(k\)-linear equivalence
213	  \[
214	    H^0_{\Module}(F) \;\simeq_k\; \Hom(\text{constant sheaf at }k,\; F).
215	  \]
216	\end{definition}
217	
218	\begin{proof}
219	  
220	  \leanok
221	  Direct from Mathlib's \(H^0\) bridge in any \(k\)-linear abelian category, applied to the sheaf category of \(k\)-modules. The \(k\)-linear enrichment is auto-inferable from the sheafification hypothesis.
222	\end{proof}
223	
224	\begin{remark}[Choice of linear equivalence]
225	  Mathlib provides three flavours of the \(\Ext^0 \simeq \Hom\) equivalence: plain, additive, and \(k\)-linear. We choose the \(k\)-linear refinement because it is the one consumed downstream: finiteness of \(H^0_{\Module}(F)\) over \(k\) is equivalent to finiteness of the Hom group, via transport along a \(k\)-linear equivalence.
226	\end{remark}
227	
228	\section{\v{C}ech cohomology of the structure sheaf}
229	\label{sec:moduleK_cech}
230	
231	This section opens Path~2 of Phase~A step~6: the \v{C}ech-cohomology approach to Serre finiteness. The \v{C}ech complex of a sheaf with respect to an indexed open cover is the standard alternating-coface complex; its cohomology in each degree lives in the category of \(k\)-modules.
232	
233	\begin{definition}\leanok
234	[\v{C}ech complex of the structure sheaf]
235	  \label{def:Scheme_cechCochain_OC}
236	  \lean{AlgebraicGeometry.Scheme.cechCochain_OC}
237	  
238	  Let \(C\) be a scheme over \(\Spec k\) and \(\mathcal U\) an indexed family of opens of \(C\). Define the \v{C}ech cochain complex of the structure sheaf with respect to \(\mathcal U\) to be the standard \v{C}ech complex applied to the underlying presheaf of the \(k\)-module-valued structure sheaf. This is a cochain complex valued in \(k\)-modules, indexed by \(\mathbb N\).
239	\end{definition}
240	
241	\begin{definition}\leanok
242	[\v{C}ech cohomology of the structure sheaf]
243	  \label{def:Scheme_cechCohomology_OC}
244	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC}
245	  
246	  With \((C, \mathcal U)\) as in Definition~REF, define the \(n\)-th \v{C}ech cohomology to be the \(n\)-th homology of the \v{C}ech cochain complex. The result lives in the category of \(k\)-modules.
247	\end{definition}
248	
249	\begin{remark}
250	  This section defines the \v{C}ech carriers but does not prove that \v{C}ech cohomology agrees with derived-functor cohomology. The comparison theorem requires the cover to be acyclic, and is queued for a subsequent iteration.
251	\end{remark}
252	
253	\section{Cohomology of an open in \(k\)-module flavor}
254	\label{sec:hmodule_prime}
255	
256	We introduce a second cohomology carrier: cohomology of an open, parameterised by the open set \(X\). This is the API entry point that downstream Mayer--Vietoris LES and \v{C}ech-vs-derived comparison theorems both consume.
257	
258	\begin{definition}\leanok
259	[Cohomology of an open with \(k\)-module coefficients]
260	  \label{def:Scheme_HModule_prime}
261	  \lean{AlgebraicGeometry.Scheme.HModule'}
262	  
263	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules and \(\Ext\), and \(F\) a sheaf of \(k\)-modules. For \(n \in \mathbb N\) and \(X\) an object of \(C\):
264	  \[
265	    H^{\prime n}(X, F) \;:=\; \Ext^n\bigl(\text{sheafified representable at }X,\; F\bigr) \;\in\; \mathrm{Type}.
266	  \]
267	  The underlying type carries a \(k\)-module structure through the same \(\Ext\) mechanism that powers \(H_{\Module}\).
268	\end{definition}
269	
270	\begin{remark}
271	  The reducible wrapper is required for the same reason as in Definition~REF: instance synthesis must see through to the underlying \(\Ext\) group.
272	\end{remark}
273	
274	\section{The \(H^0\) algebraic bridge for cohomology of an open}
275	\label{sec:hmodule_prime_zero}
276	
277	Parallel to Definition~REF, we identify the degree-zero piece of cohomology of an open with a Hom group.
278	
279	\begin{definition}\leanok
280	[\(H^0\) as a \(k\)-linear Hom group, open flavor]
281	  \label{def:Scheme_HModule_prime_zero_linearEquiv}
282	  \lean{AlgebraicGeometry.Scheme.HModule'_zero_linearEquiv}
283	  
284	  Let \(k\) be a field, \(C\) a Grothendieck site, \(X\) an object of \(C\), and \(F\) a sheaf of \(k\)-modules. Then there is a canonical \(k\)-linear equivalence
285	  \[
286	    H^{\prime 0}(X, F) \;\simeq_k\; \Hom(\text{sheafified representable at }X,\; F).
287	  \]
288	\end{definition}
289	
290	\begin{proof}
291	  
292	  \leanok
293	  Direct from the \(H^0\) bridge in any \(k\)-linear abelian category, applied to the sheaf category of \(k\)-modules.
294	\end{proof}
295	
296	\begin{remark}
297	  Together with Definition~REF, the two \(H^0\) bridges provide the algebraic preliminaries for both the global and open-local cohomology theories. The substantive Mayer--Vietoris LES theorem is built on these carriers in Chapter~REF.
298	\end{remark}
299	
300	\section{\(k\)-finite transport companions for the \(H^0\) bridges}
301	\label{sec:HModule_finite_zero_iter038}
302	
303	After the \(H^0\) bridges identify cohomology with Hom groups, the immediate companion is transport of finite-dimensionality: if the Hom group is finite-dimensional over \(k\), so is the cohomology group.
304	
305	\begin{theorem}\leanok
306	[\(k\)-finite transport for global \(H^0\)]
307	  \label{thm:Scheme_module_finite_HModule_zero}
308	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero}
309	  
310	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules and \(\Ext\), and \(F\) a sheaf of \(k\)-modules. If the \(k\)-linear Hom group \(\Hom(\text{constant sheaf at }k, F)\) is finite-dimensional over \(k\), then \(H^0_{\Module}(F)\) is also finite-dimensional over \(k\).
311	\end{theorem}
312	
313	\begin{proof}
314	  
315	  \leanok
316	  Transport finite-dimensionality across the symmetric form of the \(H^0\) bridge.
317	\end{proof}
318	
319	\begin{theorem}\leanok
320	[\(k\)-finite transport for open \(H^0\)]
321	  \label{thm:Scheme_module_finite_HModule_prime_zero}
322	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero}
323	  
324	  Let \(k\) be a field, \(C\) a Grothendieck site, \(X\) an object of \(C\), and \(F\) a sheaf of \(k\)-modules. If the \(k\)-linear Hom group \(\Hom(\text{sheafified representable at }X, F)\) is finite-dimensional over \(k\), then \(H^{\prime 0}(X, F)\) is also finite-dimensional over \(k\).
325	\end{theorem}
326	
327	\begin{proof}
328	  
329	  \leanok
330	  Transport finite-dimensionality across the symmetric form of the open \(H^0\) bridge.
331	\end{proof}
332	
333	\section{Curve specialisations of the \(H^0\) finite-dimensionality transports}
334	\label{sec:HModule_finite_zero_curve_iter039}
335	
336	\begin{theorem}\leanok
337	[Curve specialisation of global \(H^0\) finite-dimensionality]
338	  \label{thm:Scheme_module_finite_HModule_zero_curve}
339	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_curve}
340	  
341	  Let \(k\) be a field and \(C\) a scheme over \(\Spec k\). If the \(k\)-linear Hom group from the constant sheaf at \(k\) to the \(k\)-module-valued structure sheaf is finite-dimensional over \(k\), then \(H^0_{\Module}(\mathcal O_C)\) is finite-dimensional over \(k\).
342	\end{theorem}
343	
344	\begin{theorem}\leanok
345	[Curve specialisation of open \(H^0\) finite-dimensionality]
346	  \label{thm:Scheme_module_finite_HModule_prime_zero_curve}
347	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero_curve}
348	  
349	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(U\) an open of \(C\). If the \(k\)-linear Hom group from the sheafified representable at \(U\) to the \(k\)-module-valued structure sheaf is finite-dimensional over \(k\), then \(H^{\prime 0}(U, \mathcal O_C)\) is finite-dimensional over \(k\).
350	\end{theorem}
351	
352	\section{Affine cohomology vanishing carrier predicate}
353	\label{sec:IsAffineHModuleVanishing_iter040}
354	
355	To use a Mayer--Vietoris argument on a 2-affine cover, one needs the positive-degree cohomology of each affine piece to vanish. This is Serre's classical theorem on affine schemes. Since a full scheme-level proof is not yet available in the library, we package the vanishing statement as a hypothesis class.
356	
357	\begin{definition}\leanok
358	[Affine cohomology vanishing carrier predicate]
359	  \label{thm:Scheme_IsAffineHModuleVanishing}
360	  \lean{AlgebraicGeometry.Scheme.IsAffineHModuleVanishing}
361	  
362	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules on \(C\). The class of affine cohomology vanishing for \(F\) asserts that for every affine open \(U\) of \(C\) and every degree \(i > 0\), the open-evaluation cohomology \(H^{\prime i}(U, F)\) is a subsingleton (equivalently, the zero \(k\)-module).
363	\end{definition}
364	
365	\begin{theorem}\leanok
366	[Finite-dimensionality from affine vanishing]
367	  \label{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing}
368	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_isAffineHModuleVanishing}
369	  
370	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules. Assume affine cohomology vanishing holds for \(F\). For any affine open \(U\) of \(C\) and any \(i > 0\), the cohomology group \(H^{\prime i}(U, F)\) is finite-dimensional over \(k\).
371	\end{theorem}
372	
373	\begin{proof}
374	  
375	  \leanok
376	  A subsingleton \(k\)-module is generated by the empty set, hence finitely generated and finitely presented, hence finite-dimensional.
377	\end{proof}
378	
379	\section{\(H^0\) Hom-finiteness carrier predicate}
380	\label{sec:IsAffineHModuleHomFinite_iter041}
381	
382	Parallel to the affine vanishing class, we package the \(H^0\) side as a class-style predicate: on each affine open, the Hom group (morally, the sections) is finite-dimensional over \(k\).
383	
384	\begin{definition}\leanok
385	[\(H^0\) Hom-finiteness carrier predicate]
386	  \label{thm:Scheme_IsAffineHModuleHomFinite}
387	  \lean{AlgebraicGeometry.Scheme.IsAffineHModuleHomFinite}
388	  
389	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules on \(C\). The class of \(H^0\) Hom-finiteness for \(F\) asserts that for every affine open \(U\) of \(C\), the morphism group from the sheafified representable at \(U\) to \(F\) is finite-dimensional over \(k\).
390	\end{definition}
391	
392	\begin{theorem}\leanok
393	[Finite-dimensionality of open \(H^0\) from Hom-finiteness]
394	  \label{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
395	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero_of_isAffineHModuleHomFinite}
396	  
397	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules. Assume \(H^0\) Hom-finiteness holds for \(F\). For any affine open \(U\) of \(C\), the cohomology group \(H^{\prime 0}(U, F)\) is finite-dimensional over \(k\).
398	\end{theorem}
399	
400	\begin{proof}
401	  
402	  \leanok
403	  Apply the class hypothesis and transport finite-dimensionality across the \(H^0\) algebraic bridge.
404	\end{proof}
405	
406	\section{Combined affine-corner finite-dimensionality consumer}
407	\label{sec:module_finite_HModule_prime_of_affine_iter042}
408	
409	The two consumers above each cover one degree side: the \(H^0\) consumer requires \(i = 0\), the positive-degree consumer requires \(i > 0\). We fold both into a single uniform statement covering all \(i \ge 0\).
410	
411	\begin{theorem}\leanok
412	[Combined affine-corner finite-dimensionality]
413	  \label{thm:Scheme_module_finite_HModule_prime_of_affine}
414	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_affine}
415	  
416	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules. Assume both affine cohomology vanishing and \(H^0\) Hom-finiteness hold for \(F\). For any affine open \(U\) of \(C\) and any \(i \ge 0\), the cohomology group \(H^{\prime i}(U, F)\) is finite-dimensional over \(k\).
417	\end{theorem}
418	
419	\begin{proof}
420	  
421	  \leanok
422	  Case-split on whether \(i = 0\) or \(i > 0\), delegating to the respective consumer.
423	\end{proof}
424	
425	\begin{theorem}\leanok
426	[Curve specialisation]
427	  \label{thm:Scheme_module_finite_HModule_prime_of_affine_curve}
428	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_affine_curve}
429	  
430	  Direct curve specialisation of Theorem~REF to \(F = \mathcal O_C\) for \(C\) a scheme over \(\Spec k\).
431	\end{theorem}
432	
433	\begin{proof}\uses{thm:Scheme_module_finite_HModule_prime_of_affine}
434	  Apply \cref{thm:Scheme_module_finite_HModule_prime_of_affine} with the
435	  sheaf of \(k\)-modules taken to be the structure sheaf \(F = \mathcal O_C\):
436	  the affine cohomology-vanishing and \(H^0\) Hom-finiteness hypotheses are
437	  exactly the curve hypotheses available for \(\mathcal O_C\), so every
438	  \(H^{\prime i}(U, \mathcal O_C)\) over an affine open \(U\) is
439	  finite-dimensional over \(k\). Proved directly in Lean.
440	\end{proof}
441	
442	\section{Wholespace \(H^0\) Hom-finiteness carrier}
443	\label{sec:IsHModuleHomFinite_iter043}
444	
445	The affine-quantified \(H^0\) Hom-finiteness class of Section~REF over-quantifies: on a non-trivial proper curve, sections over a proper affine open are typically infinite-dimensional over \(k\) (e.g. \(k[t]\) on \(\mathbb A^1_k\)). We introduce a corrective carrier that captures only the \emph{global} Hom group.
446	
447	\begin{definition}\leanok
448	[Wholespace \(H^0\) Hom-finiteness carrier predicate]
449	  \label{thm:Scheme_IsHModuleHomFinite}
450	  \lean{AlgebraicGeometry.Scheme.IsHModuleHomFinite}
451	  
452	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules on \(C\). The class of wholespace \(H^0\) Hom-finiteness asserts that the global morphism group \(\Hom(\text{constant sheaf at }k, F)\) is finite-dimensional over \(k\).
453	\end{definition}
454	
455	\begin{theorem}\leanok
456	[Finite-dimensionality of global \(H^0\) from wholespace Hom-finiteness]
457	  \label{thm:Scheme_module_finite_HModule_zero_of_isHModuleHomFinite}
458	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_of_isHModuleHomFinite}
459	  
460	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules. Assume wholespace \(H^0\) Hom-finiteness holds for \(F\). Then \(H^0_{\Module}(F)\) is finite-dimensional over \(k\).
461	\end{theorem}
462	
463	\begin{theorem}\leanok
464	[Curve specialisation]
465	  \label{thm:Scheme_module_finite_HModule_zero_of_isHModuleHomFinite_curve}
466	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_of_isHModuleHomFinite_curve}
467	  
468	  Direct curve specialisation of Theorem~REF to \(F = \mathcal O_C\).
469	\end{theorem}
470	
471	\begin{remark}
472	  On a proper geometrically connected curve, Stein factorization gives \(\Gamma(C, \mathcal O_C) = k\), which is finite-dimensional over \(k\). Thus the wholespace carrier is producible, unlike the affine-quantified version.
473	\end{remark}
474	
475	\section{Stein finiteness of global sections}
476	\label{sec:module_finite_globalSections_iter044}
477	
478	The geometric input for the wholespace Hom-finiteness carrier is Stein's theorem: on a proper integral scheme over a field, global sections are finite-dimensional.
479	
480	\begin{theorem}\leanok
481	[Stein finiteness of global sections]
482	  \label{thm:Scheme_module_finite_globalSections_of_isProper}
483	  \lean{AlgebraicGeometry.Scheme.module_finite_globalSections_of_isProper}
484	  
485	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then \(\Gamma(C, \mathcal O_C)\) is finite-dimensional over \(k\).
486	\end{theorem}
487	
488	\begin{proof}
489	  
490	  \leanok
491	  Apply the theorem that for an integral scheme with a universally closed, locally finite-type morphism to \(\Spec k\), the structure-morphism ring map on global sections is module-finite. Transfer the base ring from \(\Gamma(\Spec k, \top)\) to \(k\) along the canonical ring isomorphism.
492	\end{proof}
493	
494	\section{Global-sections evaluation isomorphism}
495	\label{sec:gammaObj_linearEquiv_top}
496	
497	To bridge from global sections (a concrete \(k\)-module) to the abstract Hom-from-constant-sheaf form, we lift the natural isomorphism between global sections and evaluation at the terminal object to a \(k\)-linear equivalence.
498	
499	\begin{theorem}\leanok
500	[Global-sections-to-top linear equivalence]
501	  \label{thm:Scheme_SheafGammaObj_linearEquiv_top}
502	  \lean{AlgebraicGeometry.Scheme.SheafGammaObj_linearEquiv_top}
503	  
504	  Let \(k\) be a field, \(X\) a topological space, and \(F\) a sheaf of \(k\)-modules on \(X\). Then there is a \(k\)-linear equivalence between the global-sections object of \(F\) and the evaluation of \(F\) at the top open \(\top\).
505	\end{theorem}
506	
507	\begin{theorem}\leanok
508	[Finite-dimensionality on global-sections object]
509	  \label{thm:Scheme_module_finite_gammaObj_of_isProper}
510	  \lean{AlgebraicGeometry.Scheme.module_finite_gammaObj_of_isProper}
511	  
512	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then the global-sections object of the \(k\)-module-valued structure sheaf is finite-dimensional over \(k\).
513	\end{theorem}
514	
515	\begin{proof}
516	  
517	  \leanok
518	  Combine Theorem~REF with the linear equivalence of Theorem~REF, transporting finite-dimensionality across the symmetric form.
519	\end{proof}
520	
521	\section{Producer instance for wholespace Hom-finiteness}
522	\label{sec:IsHModuleHomFinite_producer}
523	
524	We now assemble the chain: constant-sheaf/global-sections adjunction, Hom-from-\(k\) evaluation, and Stein finiteness, to produce the wholespace \(H^0\) Hom-finiteness instance.
525	
526	\begin{lemma}\leanok
527	[Linear lifting of adjoint functors]
528	  \label{lemma:Adjunction_left_adjoint_linear}
529	  \lean{CategoryTheory.Adjunction.left_adjoint_linear}
530	  Let \(F \dashv G\) be an adjunction between \(R\)-linear preadditive categories. If \(G\) is \(R\)-linear, then \(F\) is \(R\)-linear.
531	\end{lemma}
532	
533	\begin{lemma}\leanok
534	[Right-adjoint version]
535	  \label{lemma:Adjunction_right_adjoint_linear}
536	  \lean{CategoryTheory.Adjunction.right_adjoint_linear}
537	  Dual of Lemma~REF: if \(F\) is \(R\)-linear, then \(G\) is \(R\)-linear.
538	\end{lemma}
539	
540	\begin{theorem}\leanok
541	[Linear hom-equivalence from an adjunction]
542	  \label{def:Adjunction_homLinearEquiv}
543	  \lean{CategoryTheory.Adjunction.homLinearEquiv}
544	  
545	  Let \(F \dashv G\) be an adjunction between \(R\)-linear preadditive categories with \(G\) additive and \(R\)-linear. Then for all objects \(X\) and \(Y\), the additive equivalence of the adjunction upgrades to an \(R\)-linear equivalence between \(\Hom(FX, Y)\) and \(\Hom(X, GY)\).
546	\end{theorem}
547	
548	\begin{theorem}\leanok
549	[Constant-sheaf / global-sections linear equivalence]
550	  \label{def:Scheme_constantSheafGammaHom_linearEquiv}
551	  \lean{AlgebraicGeometry.Scheme.constantSheafGammaHom_linearEquiv}
552	  
553	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules, and \(F\) a sheaf of \(k\)-modules. For any \(k\)-module \(X\), there is a \(k\)-linear equivalence between morphisms from the constant sheaf at \(X\) to \(F\), and \(k\)-linear maps from \(X\) to the global sections of \(F\).
554	\end{theorem}
555	
556	\begin{theorem}\leanok
557	[Hom-from-\(k\) evaluation]
558	  \label{def:Scheme_homFromOne_linearEquiv}
559	  \lean{AlgebraicGeometry.Scheme.homFromOne_linearEquiv}
560	  For any field \(k\) and \(k\)-module \(M\), there is a canonical \(k\)-linear equivalence between \(\Hom_k(k, M)\) and \(M\) given by evaluation at \(1\).
561	\end{theorem}
562	
563	\begin{theorem}\leanok
564	[Producer instance for wholespace Hom-finiteness]
565	  \label{inst:Scheme_instIsHModuleHomFinite_toModuleKSheaf}
566	  \lean{AlgebraicGeometry.Scheme.instIsHModuleHomFinite_toModuleKSheaf}
567	  
568	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then wholespace \(H^0\) Hom-finiteness holds for the \(k\)-module-valued structure sheaf of \(C\).
569	\end{theorem}
570	
571	\begin{proof}
572	  
573	  \leanok
574	  Compose the constant-sheaf/global-sections linear equivalence (specialised to \(X = k\)) with the Hom-from-\(k\) evaluation to obtain a linear equivalence between the global Hom group and the global-sections object. Theorem~REF provides finite-dimensionality on the latter; transport across the symmetric form of the equivalence.
575	\end{proof}
576	
577	\begin{remark}
578	  Once this producer instance is registered, the consumer of Theorem~REF fires automatically, closing \(H^0_{\Module}(\mathcal O_C)\) finite-dimensionality for proper integral curves.
579	\end{remark}
580	
581	\section{Foundational parameterised \v{C}ech infrastructure}
582	\label{sec:moduleK_cech_parameterised}
583	
584	We generalise the \v{C}ech carriers from the structure sheaf to an arbitrary sheaf of \(k\)-modules, laying the scaffolding for the \v{C}ech-vs-derived comparison theorem.
585	
586	\begin{definition}\leanok
587	[Parameterised \v{C}ech complex]
588	  \label{def:Scheme_cechCochain}
589	  \lean{AlgebraicGeometry.Scheme.cechCochain}
590	  
591	  Let \(C\) be a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules on \(C\), and \(\mathcal U\) an indexed family of opens. Define the \v{C}ech cochain complex of \(F\) with respect to \(\mathcal U\) to be the standard \v{C}ech complex applied to the underlying presheaf of \(F\). This is a cochain complex valued in \(k\)-modules.
592	\end{definition}
593	
594	\begin{definition}\leanok
595	[Parameterised \v{C}ech cohomology]
596	  \label{def:Scheme_cechCohomology}
597	  \lean{AlgebraicGeometry.Scheme.cechCohomology}
598	  
599	  With \((C, F, \mathcal U)\) as in Definition~REF, define the \(n\)-th \v{C}ech cohomology to be the \(n\)-th homology of the \v{C}ech cochain complex.
600	\end{definition}
601	
602	\begin{theorem}\leanok
603	[\v{C}ech complex bridge to structure-sheaf specialisation]
604	  \label{thm:Scheme_cechCochain_OC_eq}
605	  \lean{AlgebraicGeometry.Scheme.cechCochain_OC_eq}
606	  
607	  The structure-sheaf \v{C}ech complex equals the parameterised \v{C}ech complex at \(F = \mathcal O_C\).
608	\end{theorem}
609	
610	\begin{theorem}\leanok
611	[\v{C}ech cohomology bridge to structure-sheaf specialisation]
612	  \label{thm:Scheme_cechCohomology_OC_eq}
613	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC_eq}
614	  
615	  The structure-sheaf \v{C}ech cohomology equals the parameterised \v{C}ech cohomology at \(F = \mathcal O_C\).
616	\end{theorem}
617	
618	\begin{remark}
619	  These generalisations do not construct any comparison map between \v{C}ech and derived cohomology, nor do they prove vanishing. The substantive work is queued for subsequent iterations.
620	\end{remark}
621	
622	\section{\v{C}ech-side acyclicity carrier}
623	\label{sec:moduleK_cech_acyclic_cover}
624	
625	We introduce a carrier predicate capturing positive-degree vanishing of \v{C}ech cohomology, together with a consumer that transports this vanishing to derived cohomology once a comparison isomorphism is available.
626	
627	\begin{definition}\leanok
628	[\v{C}ech acyclicity carrier predicate]
629	  \label{def:Scheme_IsCechAcyclicCover}
630	  \lean{AlgebraicGeometry.Scheme.IsCechAcyclicCover}
631	  
632	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules on \(C\), and \(\mathcal U\) an indexed family of opens. The cover \(\mathcal U\) is \v{C}ech-acyclic for \(F\) if the \v{C}ech cohomology vanishes in positive degrees: for every \(n \ge 1\), the \(n\)-th \v{C}ech cohomology group is a subsingleton.
633	\end{definition}
634	
635	\begin{theorem}\leanok
636	[Derived vanishing from \v{C}ech acyclicity]
637	  \label{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover}
638	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule'_supr_of_isCechAcyclicCover}
639	  
640	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules, and \(\mathcal U\) a \v{C}ech-acyclic cover for \(F\). Suppose there is a \(k\)-linear comparison isomorphism between \v{C}ech cohomology and derived cohomology of the cover supremum for every degree. Then for every \(n \ge 1\), the derived cohomology of the cover supremum is a subsingleton.
641	\end{theorem}
642	
643	\begin{proof}
644	  
645	  \leanok
646	  Transport the subsingleton structure along the symmetric form of the comparison isomorphism.
647	\end{proof}
648	
649	\begin{theorem}\leanok
650	[Curve specialisation]
651	  \label{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover_curve}
652	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule'_supr_of_isCechAcyclicCover_curve}
653	  
654	  Curve specialisation of Theorem~REF at \(F = \mathcal O_C\).
655	\end{theorem}
656	
657	\section{Use in the project}
658	
659	The composition of the four typeclass instances of Sections~REF--REF, Definition~REF, and Definition~REF delivers Phase~A step~5 in full and bridges to Phase~A step~6:
660	
661	\begin{itemize}
662	  \item For \(C\) a scheme over \(\Spec k\), the \(k\)-module-valued cohomology \(H^n_{\Module}(\mathcal O_C)\) is well-defined and automatically carries a \(k\)-module structure, so \(\dim_k H^n_{\Module}(\mathcal O_C)\) is well-defined.
663	  \item Forgetting the \(k\)-module structure recovers the abelian-group cohomology of Chapter~REF, so the two theories commute on the underlying type level.
664	  \item Phase~A step~6 (Serre finiteness) remains the deep work to come, but is now expressible inside the standard \(k\)-module API: the statement becomes the finite-dimensionality predicate on \(H^n_{\Module}(F)\).
665	\end{itemize}
